const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const quote = (
  _customer: Customer,
  items: Item[],
  _priorContracts: number,
): number => {
  let total = 0;
  for (const item of items) {
    const base = BASE_PREMIUM[item.type];
    total += base + base * 0.1;
  }
  return total + PROCESSING_FEE;
